module.exports = /*#__PURE__*/JSON.parse('{"navigation":{"home":"Beranda","about":"Tentang","services":"Layanan","gallery":"Galeri","contact":"Kontak","articles":"Wawasan","careers":"Karir","menu":"Menu"},"header":{"contactCta":"Hubungi Glassbox","contactCtaShort":"Hubungi"},"articlesPage":{"title":"Wawasan","subtitle":"Ide untuk media modern dan OOH","description":"Sudut pandang praktis tentang OOH, DOOH, digital signage, media transit, dan aktivasi merek di Indonesia.","readMore":"Baca artikel","backToList":"Semua wawasan","published":"Dipublikasikan","items":{"ooh-vs-dooh-panduan-merek-indonesia":{"title":"OOH vs DOOH: apa bedanya dan kapan memakai masing-masing?","date":"2026-04-28","excerpt":"Out-of-home klasik (vinil, billboard cetak, stiker) dan digital out-of-home (layar terjadwal) memenuhi fungsi berbeda dalam funnel. Panduan singkat untuk tim merek di Indonesia.","paragraphs":["OOH tradisional unggul pada massa visual besar, biaya produksi per tayang rendah untuk periode panjang, dan kehadiran permanen di satu lokasi ikonik—cocok untuk awareness jangka menengah ketika pesan tidak berubah setiap hari.","DOOH menambahkan fleksibilitas: ganti kreatif cepat, penjadwalan menurut waktu atau konteks, dan peluang integrasi data untuk optimasi berulang—ideal untuk promo terbatas, peluncuran produk, atau A/B di lapangan.","Kombinasi sering paling kuat: DOOH di koridor dan ritel padat untuk frekuensi dan relevansi, ditambah OOH statis di landmark atau kampanye musiman untuk jejak visual yang tebal. Glassbox membantu merek merancang campuran itu agar operasionalnya tetap ringan."]},"metrik-dooh-proof-of-play-indonesia":{"title":"Metrik DOOH di Indonesia: proof of play, tayang, dan cara membaca laporan","date":"2026-04-27","excerpt":"Pengiklan digital terbiasa dengan impresi dan klik; DOOH memakai istilah lain. Memahami proof of play dan definisi tayang membantu menyelaraskan ekspektasi dengan mitra media.","paragraphs":["Proof of play adalah bukti bahwa konten benar-benar tayang sesuai jadwal—lewat log perangkat, tangkapan audit, atau laporan jaringan. Ini dasar akuntabilitas sebelum membahas angka jangkauan.","Estimasi impresi DOOH biasanya memadukan data lalu lintas pejalan kaki atau kendaraan dengan asumsi visibilitas layar; metode antar penyedia bisa berbeda, jadi bandingkan apel dengan apel saat mengevaluasi proposal.","Mulai dari KPI sederhana: tayang terjadwal vs aktual, konsistensi durasi spot, dan kesesuaian lokasi dengan target audiens. Dari situ merek bisa menambah metrik lanjutan seiring kedalaman kerja sama."]},"dooh-kreatif-durasi-zona-aman-indonesia":{"title":"Kreatif DOOH: durasi tayang, zona aman, dan membaca dari jarak jauh","date":"2026-04-26","excerpt":"Layar publik bukan feed ponsel: waktu melihat pendek dan jarak bervariasi. Berikut praktik desain yang menjaga merek tetap jelas tanpa memaksakan terlalu banyak informasi.","paragraphs":["Aturan praktis: satu ide utama per versi, tipografi besar, kontras tinggi, dan hindari teks panjang; jika ada gerakan, pastikan pesan kunci masih terbaca pada frame pertama dan terakhir.","Zona aman menjaga logo, legal line, dan CTA tidak terpotong bezel atau frame venue; selalu uji mockup pada rasio layar yang dipakai di lapangan.","Durasi loop menentukan berapa lama audiens punya kesempatan menyerap pesan—padukan dengan lokasi: lift dan antrean memungkinkan baca lebih lama, koridor transit menuntut irama lebih cepat."]},"format-ooh-indonesia-ritel-transit-jalan":{"title":"Format OOH & DOOH di Indonesia: ritel, transit, dan jalan raya","date":"2026-04-24","excerpt":"Dari layar di mal hingga tubuh kendaraan dan struktur jalan—setiap format punya ritme audiens berbeda. Ringkasan untuk perencanaan media luar ruang.","paragraphs":["Ritel dan mal menawarkan konteks belanja serta pengulangan paparan dalam satu kunjungan; DOOH di sini mendukung pesan yang bisa diperbarui sesuai promo atau waktu buka tutup tenant.","Transit—bus, halte, stasiun—menjangkau perjalanan harian dengan pola frekuensi mingguan; kreatif harus tahan gangguan visual lingkungan dan tetap terbaca saat orang bergerak.","Jalan raya dan struktur vertikal memberi jangkauan luas untuk awareness; biasanya membutuhkan pesan sangat ringkas dan identitas merek yang kuat agar tetap diingat setelah sekali lihat."]},"social-commerce-kreator-indonesia-ooh":{"title":"Social commerce & kreator di Indonesia: melengkapi jangkauan dengan OOH","date":"2026-04-18","excerpt":"Kolaborasi dengan nano- dan micro-kreator serta kampanye berbasis kinerja sedang jadi fokus banyak merek. Tanpa saluran fisik, pesan sering berhenti di dalam feed.","paragraphs":["Di Indonesia, belanja melalui konten pendek dan siaran langsung berkembang cepat; audiens terbiasa menemukan produk dari host dan kreator yang mereka percayai.","Kampanye berbasis kinerja menuntut metrik jelas—jangkauan, interaksi, konversi—namun algoritme dan biaya platform bisa mengubah aturan main dalam semalam.","OOH dan digital signage di mal, transit, atau venue strategis memperluas cerita yang sama ke luar layar ponsel: pengingat merek di dunia nyata tanpa menggantikan peran kreator."]},"ai-search-brand-discovery-indonesia-2026":{"title":"Pencarian berbantuan AI dan visibilitas merek: apa artinya untuk pasar Indonesia?","date":"2026-04-14","excerpt":"Semakin banyak orang memulai pencarian lewat asisten AI, bukan hanya mesin telusur klasik. Merek perlu kombinasi konten, data pertama, dan kehadiran nyata.","paragraphs":["Tren global menunjukkan pergeseran dari daftar tautan biru menuju jawaban ringkas yang disintesis; di Indonesia, perilaku pencarian mobile yang dominan mempercepat eksperimen format baru.","Ketika jawaban dibuatkan oleh model, merek yang mengandalkan sekadar iklan tayang bisa kehilangan narasi: aset yang terukur—situs, aplikasi, komunitas, dan pengalaman fisik—semakin penting.","Kehadiran di jalan, ritel, dan transit membantu merek tetap dikenali di luar kotak dialog AI: satu pesan konsisten di banyak konteks memperkuat ingatan dan kepercayaan."]},"video-pendek-live-commerce-titik-fisik-indonesia":{"title":"Video pendek & live commerce: mengapa titik fisik tetap relevan di Indonesia","date":"2026-04-10","excerpt":"Format vertikal dan sesi belanja langsung mendominasi perhatian digital. Merek yang hanya berinvestasi di dalam aplikasi sering kehilangan momen niat di dunia nyata.","paragraphs":["Konsumen Indonesia menghabiskan banyak waktu untuk video pendek dan konten belanja terintegrasi; kreatif yang kuat di sana adalah syarat, bukan pembeda tunggal.","Live commerce membangun kepercayaan lewat interaksi real time, tetapi jangkauan bergantung pada platform dan jadwal—kampanye besar masih membutuhkan pengingat di luar ekosistem tersebut.","Layar di lokasi berdampak tinggi—koridor mal, area tunggu, transportasi—menjembatani hype digital dengan konteks belanja dan perjalanan sehari-hari, tempat keputusan tetap terjadi."]},"retail-media-network-indonesia":{"title":"Retail media network: mengapa layar di ritel jadi aset strategis","date":"2026-04-08","excerpt":"Ritel memonetisasi audiens dengan jaringan layar sendiri; merek pengiklan mendapat konteks belanja yang kuat. Pelajari dinamika win-win dan apa artinya untuk kampanye Anda.","paragraphs":["Retail media network menggabungkan titik kontak fisik—koridor mal, area kasir, lift parkir—dengan inventori layar yang dapat dijadwalkan. Bagi pengiklan, ini berarti pesan muncul dekat momen niat beli, bukan sekadar tayang massal.","Kunci suksesnya transparansi: pemilik venue, pembeli media, dan merek perlu memahami frekuensi, zona tayang, dan batas konten agar pengalaman belanja tetap nyaman.","Glassbox berada di persimpangan penempatan media modern: kami membantu merek memanfaatkan konteks ritel dengan kreatif yang mudah dibaca dan operasi yang ringan bagi mitra lokasi."]},"ai-kreatif-dan-konteks-dooh":{"title":"AI untuk kreatif DOOH: variasi, uji cepat, dan konteks tayang","date":"2026-03-18","excerpt":"Alat bantu AI mempercepat ide dan variasi visual—tetapi layar publik menuntut pesan yang tegas dan aman. Berikut cara memanfaatkannya tanpa mengorbankan kejelasan.","paragraphs":["Generative AI berguna untuk eksplorasi mood board, headline alternatif, dan variasi layout sebelum produksi final. Yang tidak berubah: aturan baca sekilas—satu ide utama, kontras tinggi, teks pendek.","Di DOOH, setiap variasi harus lolos uji jarak dan waktu tayang singkat; AI membantu volume ide, manusia tetap mengunci standar merek dan kepatuhan.","Kampanye yang kuat memadukan otomatisasi di belakang layar dengan kurasi ketat di lapangan: jadwal, lokasi, dan pesan diselaraskan agar audiens tidak kebingungan."]},"programmatic-dooh-data-driven-indonesia":{"title":"DOOH terprogram dan iklan berbasis data di Indonesia: mulai dari mana?","date":"2026-02-10","excerpt":"Pembelian inventori digital out-of-home semakin mirip iklan online: kelompok audiens, frekuensi, dan bukti tayang. Ini ringkasan praktis bagi merek yang ingin mencoba tanpa kehilangan kendali merek.","paragraphs":["Programmatic DOOH memungkinkan penjadwalan dan penargetan berdasarkan konteks—waktu, lokasi, atau paket audiens—dengan fleksibilitas yang sulit dicapai media statis.","Di pasar Indonesia, langkah pertama biasanya menyelaraskan sasaran kampanye dengan jaringan yang tersedia: koridor transit, cluster ritel, atau venue khusus, lalu menetapkan metrik sederhana seperti reach dan frekuensi.","Glassbox mendukung pendekatan bertahap: mulai dari penempatan terkurasi dengan pembaruan konten cepat, lalu memperluas ke skenario yang lebih data-driven sejalan dengan pembelajaran tim Anda."]},"digital-signage-high-traffic-retail":{"title":"Mengapa digital signage unggul di ritel padat lalu lintas","date":"2025-11-12","excerpt":"Layar di mal dan ritel menjangkau pembeli saat niat tinggi. Berikut cara merencanakan kreatif dan frekuensi untuk daya ingat maksimal.","paragraphs":["Lingkungan ritel dengan lalu lintas tinggi memberi merek paparan berulang dalam waktu singkat. Digital signage mengubah momen itu menjadi cerita yang fleksibel dan dapat diperbarui, bukan poster statis.","Program ritel terkuat memadukan kreatif tegas dan mudah dibaca dengan penjadwalan sesuai waktu—pagi sibuk berbeda dengan malam santai dalam hal apa yang orang perhatikan.","Penempatan Glassbox di jaringan mal dan ritel dirancang untuk visibilitas setinggi mata dan gesekan minimal bagi mitra venue, sehingga kampanye dapat diluncurkan dan disesuaikan dengan cepat."]},"ooh-transit-brand-visibility-indonesia":{"title":"OOH transit dan visibilitas merek di seluruh Indonesia","date":"2025-10-08","excerpt":"Penduduk kota melihat pesan Anda berkali-kali per minggu. OOH transit mengutamakan penawaran jelas, desain aman untuk gerakan, dan perencanaan berbasis rute.","paragraphs":["Media transit menjangkau orang yang bergerak namun tetap perhatian—terutama di koridor dengan waktu tunggu panjang atau perjalanan pulang-pergi mingguan yang berulang.","Kreatif harus terbaca sekilas: satu pesan utama, kontras kuat, dan satu ajakan bertindak bila memungkinkan.","Di Indonesia, memadukan koridor utama dengan layar indoor atau venue pelengkap dapat memperkuat cerita yang sama tanpa kelelahan audiens."]},"experiential-activation-offline-events":{"title":"Aktivasi pengalaman yang berlanjut setelah hari acara","date":"2025-09-20","excerpt":"Acara offline menciptakan kenangan; yang terbaik menangkap prospek dan bukti sosial agar kampanye tetap berjalan setelah booth ditutup.","paragraphs":["Pemasaran pengalaman berhasil ketika momen fisik terhubung ke langkah berikutnya yang jelas—daftar, bagikan ke sosial media, atau penawaran lanjutan.","Tampilan, sampling, dan titik interaktif harus terasa merek dan cepat digunakan; antrean panjang menurunkan konversi.","Glassbox mendukung aktivasi yang memadukan kehadiran fisik dengan tindak lanjut digital, sehingga merek dapat mengukur keterlibatan di luar lalu lintas kaki saja."]}},"slugs":["ooh-vs-dooh-panduan-merek-indonesia","metrik-dooh-proof-of-play-indonesia","dooh-kreatif-durasi-zona-aman-indonesia","format-ooh-indonesia-ritel-transit-jalan","social-commerce-kreator-indonesia-ooh","ai-search-brand-discovery-indonesia-2026","video-pendek-live-commerce-titik-fisik-indonesia","retail-media-network-indonesia","ai-kreatif-dan-konteks-dooh","programmatic-dooh-data-driven-indonesia","digital-signage-high-traffic-retail","ooh-transit-brand-visibility-indonesia","experiential-activation-offline-events"]},"services":{"mediaPlacement":"Penempatan Media","mediaPlacementDescription":"Penempatan strategis iklan Anda di lokasi-lokasi dengan lalu lintas tinggi","oohTransit":"Media Transit OOH","oohTransitDescription":"Periklanan transit out-of-home untuk visibilitas dan jangkauan maksimal","offlineEvent":"Aktivasi Acara Offline","offlineEventDescription":"Aktivasi acara offline dan solusi pemasaran pengalaman","description":"Kami menyediakan solusi periklanan komprehensif untuk membantu merek Anda menjangkau audiens yang tepat","sectionEyebrow":"Tiga pilar layanan","headlineStart":"Solusi","headlineEnd":"Strategis","exploreService":"Lihat detail","strategicSolution":"Solusi Strategis","launchCampaign":"Mulai Kampanye Anda","backToHome":"Kembali ke Beranda","notFound":"Layanan Tidak Ditemukan","standard":"Standar","excellence":"Keunggulan"},"hero":{"tagline":"Berpikir Maju, Bertindak Berani","title":"Revolusikan Merek Anda dengan Solusi Periklanan Avant-garde Glassbox","subtitle":"Tangkap Audiens Anda Di Mana Saja Mereka Berada — Dari Ritel, Transportasi Umum, dan Perhotelan, Glassbox Menyampaikan Periklanan yang Berdampak","launchCampaign":"Mulai Kampanye","exploreNetwork":"Jelajahi Jaringan"},"audience":{"title":"Menghubungkan Merek Anda ke Audiens yang Tepat","description":"Kami membantu merek terhubung dengan audiens mereka melalui strategi periklanan komprehensif yang didukung oleh teknologi canggih. Dengan penempatan di lokasi strategis seperti:","locations":{"hotel":"Hotel","transjakarta":"Transjakarta","universities":"Universitas","mall":"Mall","lounges":"Lounge","retail":"Ritel"}},"features":{"technology":"Teknologi Canggih","management":"Manajemen Real-Time","locations":"Lokasi Berdampak Tinggi"},"platforms":{"title":"Periklanan Inovatif di Multi-Platform","digitalSignage":{"title":"Digital Signage","description":"Ideal untuk area lalu lintas tinggi, menawarkan merek cara yang kuat untuk menampilkan pesan mereka dengan visual yang hidup dan pembaruan real-time.","cta":"Lihat Solusi"},"smartTV":{"title":"Smart TV","description":"Menyediakan platform ganda di mana iklan dapat terintegrasi dengan mulus ke dalam pengalaman menonton, memastikan visibilitas tinggi tanpa mengganggu audiens.","cta":"Lihat Solusi"},"tablets":{"title":"Tablet","description":"Memfasilitasi keterlibatan personal, memungkinkan merek menciptakan pengalaman yang disesuaikan yang mendorong interaksi langsung dan koneksi yang lebih dalam dengan pelanggan.","cta":"Lihat Solusi"}},"results":{"title":"Lihat Bagaimana Kami Menghasilkan Hasil","description":"Dari konsep hingga eksekusi, proyek kami dibuat dengan presisi, inovasi, dan pemahaman mendalam tentang audiens Anda","cta":"Pelajari Lebih Lanjut"},"partners":{"title":"Di Mana Kolaborasi Bertemu Inovasi","description":"Mitra kami mempercayai kami untuk memberikan solusi periklanan inovatif yang menghasilkan hasil nyata"},"cta":{"title":"Tingkatkan Keunggulan Brand Anda","button":"Mulai Kampanye Sekarang"},"testimonials":{"andriani":{"quote":"Dengan Glassbox, semua materi promosi terlihat sangat estetis dan menarik bagi semua tamu, menghidupkan suasana hotel.","author":"Ibu Andriani","position":"Direktur Penjualan & Pemasaran, Swiss-Belhotel Bogor"},"selo":{"quote":"Glassbox telah membawa tingkat inovasi baru ke kampus kami. Tampilan digital mereka tidak hanya menghasilkan pendapatan tambahan tetapi juga memberikan ruang kami tampilan futuristik yang selaras dengan lingkungan berpikir maju dari fakultas kami. Tim mereka sangat profesional dan dapat diandalkan sepanjang kemitraan. Pengalaman yang fantastis!","author":"Bapak Selo Sukardi","position":"Staf Kerjasama, Usaha, dan Hubungan Alumni, Fakultas Matematika dan Ilmu Pengetahuan Alam, Universitas Indonesia"},"amy":{"quote":"Berkemitraan dengan Glassbox telah sangat meningkatkan visibilitas 3S, memudahkan klien dan kandidat untuk menemukan kami. Paparan di lokasi premium telah meningkatkan keterlibatan kami, dan dukungan profesional mereka membuat proses berjalan lancar. Sangat direkomendasikan!","author":"Amy Damayanti","position":"Manajer Operasi PT Sigma Solusi Servis"}},"footer":{"tagline":"Mitra Anda untuk Solusi Periklanan Modern dan Bertarget.","privacy":"Kebijakan Privasi & Syarat & Ketentuan","copyright":"© 2024 glassbox"},"privacy":{"backToHome":"Kembali ke Beranda","trustSafety":"Kepercayaan & Keamanan","title":"Kebijakan","subtitle":"Privasi","lastUpdated":"Terakhir Diperbarui","sections":{"intro":{"title":"Pendahuluan","content1":"Di Glassbox, kami berkomitmen untuk melindungi privasi Anda. Kebijakan Privasi ini menjelaskan bagaimana kami mengumpulkan, menggunakan, mengungkapkan, dan melindungi informasi Anda saat Anda mengunjungi situs web kami, menggunakan layanan periklanan kami, atau berinteraksi dengan aplikasi seluler kami.","content2":"Harap baca kebijakan ini dengan saksama. Jika Anda tidak setuju dengan ketentuan kebijakan privasi ini, mohon untuk tidak mengakses situs atau menggunakan layanan kami."},"collection":{"title":"Informasi yang Kami Kumpulkan","intro":"Kami dapat mengumpulkan informasi tentang Anda dengan berbagai cara. Informasi yang mungkin kami kumpulkan meliputi:","personal":"Informasi identitas pribadi, seperti nama, alamat pengiriman, alamat email, dan nomor telepon, serta informasi demografis, seperti usia, jenis kelamin, kota asal, dan minat, yang Anda berikan secara sukarela kepada kami saat Anda mendaftar di Aplikasi atau saat Anda memilih untuk berpartisipasi dalam berbagai aktivitas.","derivative":"Informasi yang dikumpulkan server kami secara otomatis saat Anda mengakses Aplikasi, seperti tindakan asli Anda yang merupakan bagian integral dari Aplikasi, termasuk menyukai, memposting ulang, atau membalas postingan, serta interaksi lainnya dengan Aplikasi dan pengguna lain melalui file log server.","financial":"Informasi keuangan, seperti data yang terkait dengan metode pembayaran Anda (misalnya nomor kartu kredit yang valid, merek kartu, tanggal kedaluwarsa) yang mungkin kami kumpulkan saat Anda membeli, memesan, mengembalikan, menukar, atau meminta informasi tentang layanan kami.","mobile":"Informasi perangkat, seperti ID perangkat seluler, model, dan produsen perangkat Anda, serta informasi tentang lokasi perangkat Anda, jika Anda mengakses Aplikasi dari perangkat seluler."},"use":{"title":"Penggunaan Informasi Anda","intro":"Memiliki informasi yang akurat tentang Anda memungkinkan kami untuk memberikan pengalaman yang lancar, efisien, dan disesuaikan. Secara khusus, kami dapat menggunakan informasi yang dikumpulkan tentang Anda melalui Aplikasi untuk:","item1":"Membuat dan mengelola akun Anda.","item2":"Memproses transaksi Anda dan mengirimkan informasi terkait, termasuk konfirmasi pembelian dan faktur.","item3":"Meningkatkan algoritma periklanan dan kemampuan penargetan kami.","item4":"Memantau dan menganalisis penggunaan dan tren untuk meningkatkan pengalaman Anda dengan Aplikasi.","item5":"Memberi tahu Anda tentang pembaruan pada Aplikasi atau layanan kami.","item6":"Meminta umpan balik dan menghubungi Anda tentang penggunaan Aplikasi oleh Anda.","item7":"Mencegah transaksi penipuan, memantau pencurian, dan melindungi dari aktivitas kriminal."},"disclosure":{"title":"Pengungkapan Informasi Anda","intro":"Kami dapat membagikan informasi yang telah kami kumpulkan tentang Anda dalam situasi tertentu. Informasi Anda dapat diungkapkan sebagai berikut:","law":"Jika kami yakin pelepasan informasi tentang Anda diperlukan untuk menanggapi proses hukum, untuk menyelidiki atau memperbaiki potensi pelanggaran kebijakan kami, atau untuk melindungi hak, properti, dan keamanan orang lain.","thirdParty":"Kami dapat membagikan informasi Anda dengan pihak ketiga yang melakukan layanan untuk kami atau atas nama kami, termasuk pemrosesan pembayaran, analisis data, pengiriman email, layanan hosting, layanan pelanggan, dan bantuan pemasaran."},"security":{"title":"Keamanan Informasi Anda","content":"Kami menggunakan langkah-langkah keamanan administratif, teknis, dan fisik untuk membantu melindungi informasi pribadi Anda. Meskipun kami telah mengambil langkah-langkah yang wajar untuk mengamankan informasi pribadi yang Anda berikan kepada kami, harap menyadari bahwa terlepas dari upaya kami, tidak ada langkah keamanan yang sempurna atau tidak dapat ditembus, dan tidak ada metode transmisi data yang dapat dijamin terhadap intersepsi atau jenis penyalahgunaan lainnya."},"contact":{"title":"Hubungi Kami","intro":"Jika Anda memiliki pertanyaan atau komentar tentang Kebijakan Privasi ini, silakan hubungi kami di:","form":"Formulir Kontak"}}},"about":{"tagline":"Jaringan Visioner","title1":"Melampaui","title2":"Konvensional","locationsCount":"50+","locationsLabel":"Lokasi Aktif","primaryPlacement":"Penempatan Utama","strategicPresence":"Kehadiran Strategis","mediaKit":"Minta Media Kit Lengkap","exploreAll":"Jelajahi Semua Lokasi"},"contact":{"tagline":"Hubungi Kami","title1":"Mari Tingkatkan","title2":"Brand Anda Bersama","description":"Siap mendominasi lanskap digital? Tim kami siap menyusun strategi berdampak tinggi yang disesuaikan dengan brand Anda.","email":"Email Kami","phone":"Hubungi Kami","visit":"Kunjungi Kami","cardTitle":"Mulai Kampanye Anda","cardDescription":"Terhubung dengan spesialis media kami untuk menciptakan kehadiran berdampak tinggi yang selaras dengan audiens Anda.","cardButton":"Dapatkan Proposal Khusus Anda","responseTime":"Estimasi waktu respon: < 24 Jam"},"seo":{"homeTitle":"Glassbox — Digital Signage & Periklanan OOH Indonesia","homeDescription":"Tingkatkan merek Anda dengan Glassbox: digital signage, OOH transit, dan aktivasi pengalaman di ritel, transportasi, dan perhotelan di Indonesia.","privacyTitle":"Kebijakan Privasi | Glassbox","privacyDescription":"Bagaimana Glassbox mengumpulkan, menggunakan, dan melindungi informasi Anda saat menggunakan situs web dan layanan periklanan kami."},"error":{"notFound":{"title":"404","subtitle":"Halaman Tidak Ditemukan","description":"Halaman yang Anda cari tidak ada atau telah dipindahkan ke koordinat lain.","backHome":"Kembali ke Beranda"}}}');

